from abc import ABC, abstractmethodimport cv2import numpy as npimport pyautoguiclass ActionTrigger(ABC):    """blueprint for the computer whenever I want to trigger an action"""    @abstractmethod    def execute(self):        passclass ScrollableActionTrigger(ActionTrigger):    def execute(self):        pyautogui.scroll(-200)        print("\033[1;31m RED IS DETECTED: SCROLLING DOWN\033[0m")class VisionController(ABC):    @abstractmethod    def process_frame(self,frame):        passclass RedObjectController(VisionController):    def __init__ ( self,action_trigger: ActionTrigger, camera_index=0):        #Encapsulation        self.__cap = cv2.VideoCapture(camera_index, cv2.CAP_DSHOW)        self.__action_trigger = action_trigger        self._prev_y = 0        self.__red_lower = np.array([0,120,70])        self.__red_upper = np.array([10,255,255])        self.__red_lower = np.array([170,120,70])        self.__red_upper = np.array([180,255,255])